void SessionManager::handleDisconnect(SessionId id) {
    auto it = m_sessions.find(id);
    if (it == m_sessions.end()) {
        LOG_WARN("Disconnect for unknown session {}", id);
        return;
    }
    it->second->flushPending();
    it->second->releaseResources();
    m_sessions.erase(it);
    g_activeSessionCount--;
}
